<div class="grid-2"><div class="card"><h3>Add Recharge Operator</h3><form method="post" action="<?= base_url('index.php?route=admin/operators/store') ?>"><input type="hidden" name="_csrf" value="<?= csrf_token() ?>"><div class="form-group"><label>Name</label><input type="text" name="name" required></div><div class="form-group"><label>Code</label><input type="text" name="code" required></div><button class="btn btn-primary" type="submit">Add Operator</button></form></div><div class="card"><h3>Current Operators</h3><div class="table-wrap"><table><thead><tr><th>Name</th><th>Code</th><th>Status</th><th>Action</th></tr></thead><tbody><?php foreach ($operators as $operator): ?><tr><td><?= e($operator['name']) ?></td><td><?= e($operator['code']) ?></td><td><?= e($operator['status']) ?></td><td><form method="post" action="<?= base_url('index.php?route=admin/operators/toggle') ?>" class="inline-form"><input type="hidden" name="_csrf" value="<?= csrf_token() ?>"><input type="hidden" name="id" value="<?= (int)$operator['id'] ?>"><button class="btn btn-sm btn-outline">Toggle</button></form></td></tr><?php endforeach; ?></tbody></table></div></div></div>
